let dimensionData = queries.downloadFromS3.data.message;
const type = components.fileUploadsTable.selectedRow.file_name.slice(-3);
let formattedData = type === "csv" ? dimensionData : dimensionData.replace(/,/g, '\t');
const blob = new Blob([formattedData], { type: type === "csv" ? 'text/csv;charset=utf-8;' : 'text/tab-separated-values;charset=utf-8;'});
const url = URL.createObjectURL(blob);
const link = document.createElement('a');
link.href = url;
link.download = fileUploadsTable.selectedRow.file_name; // Name of the file to be downloaded
document.body.appendChild(link);
link.click();
document.body.removeChild(link);
